import React from 'react';
import type { CueModalId } from '../core/ports';
import { type CueAnchorState, useCueAnchor } from './useCueAnchor';
import { useScrollCueAnchorWhenActive } from './useScrollCueAnchorWhenActive';

export type CueAnchorProps = {
  children: (state: CueAnchorState) => React.ReactNode;
  modalId: CueModalId;
  stepKey: string;
};

const CueAnchor = ({ children, modalId, stepKey }: CueAnchorProps) => {
  const state = useCueAnchor({ modalId, stepKey });
  const setAnchorRef = useScrollCueAnchorWhenActive(state.isActive, { scrollIntoView: true });

  return (
    <div data-cue-anchor={stepKey} ref={setAnchorRef}>
      {children(state)}
    </div>
  );
};

export default CueAnchor;
